import{_ as o,o as t,c as a,ae as i}from"./chunks/framework.CyZiF_rV.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/offline/automatyczne-okreslanie-trybu-offline.md","filePath":"en/offline/automatyczne-okreslanie-trybu-offline.md"}'),n={name:"en/offline/automatyczne-okreslanie-trybu-offline.md"};function s(r,e,c,l,d,f){return t(),a("div",null,[...e[0]||(e[0]=[i('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/offline/automatyczne-okreslanie-trybu-offline.md" target="_blank" rel="noreferrer">offline/automatyczne-okreslanie-trybu-offline.md</a></p></blockquote><h2 id="automatic-offline-mode-determination" tabindex="-1">Automatic offline mode determination <a class="header-anchor" href="#automatic-offline-mode-determination" aria-label="Permalink to &quot;Automatic offline mode determination&quot;">​</a></h2><p>04.10.2025</p><p>In the case of invoices sent as online (<code>offlineMode: false</code>), the KSeF system may assign them offline mode - based on comparison of the issue date with the processing acceptance date.</p><h2 id="mechanism-algorithm" tabindex="-1">Mechanism algorithm <a class="header-anchor" href="#mechanism-algorithm" aria-label="Permalink to &quot;Mechanism algorithm&quot;">​</a></h2><p>For invoices sent as <code>offlineMode: false</code>, the system compares:</p><ul><li><strong>issue date</strong> of the invoice (<code>issueDate</code>, e.g., <code>P_1</code> for invoice compliant with FA(3)),</li><li><strong>acceptance date</strong> of the invoice in the KSeF system for further processing (<code>invoicingDate</code>).</li></ul><p>Rules:</p><ul><li>If the calendar day from <code>issueDate</code> is earlier than the calendar day from <code>invoicingDate</code> (comparison by date, not by time), the system automatically marks the invoice as <strong>offline</strong>, even if it was not declared as such.</li><li>If the day of <code>issueDate</code> and the day of <code>invoicingDate</code> are the same, the invoice remains <strong>online</strong>.</li></ul><p>The <code>invoicingDate</code> value depends on the transmission mode:</p><ul><li><strong>batch session</strong> - <code>invoicingDate</code> is the session opening time (equal to <code>dateCreated</code> returned in session status - GET <code>/sessions/{referenceNumber}</code>),</li><li><strong>interactive session</strong> - <code>invoicingDate</code> is the invoice transmission time.</li></ul><p>This means that if, for example, an invoice was issued on 2025-10-03 (<code>P_1</code>) and sent on 2025-10-04 at 00:00:01, despite offlineMode: false, it will be marked as an offline invoice.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p><strong>Batch session</strong> opened at 23:59:59 on October 3rd: Even if the package is sent after midnight, invoices will remain online – because <code>invoicingDate</code> is October 3rd (session opening date).</p><p><strong>Interactive session</strong> started at 23:59:59 on October 3rd, and invoices were sent after midnight: If <code>P_1</code> = 2025-10-03, the system will mark them as offline – because the day of <code>P_1</code> is earlier than the transmission day.</p><h2 id="related-documents" tabindex="-1">Related documents <a class="header-anchor" href="#related-documents" aria-label="Permalink to &quot;Related documents&quot;">​</a></h2><ul><li><a href="./../tryby-offline.html">Offline modes</a></li></ul>',17)])])}const u=o(n,[["render",s]]);export{h as __pageData,u as default};
